package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricPrompt;

public class LoginActivity extends AppCompatActivity {

    private EditText usernameEt;
    private EditText passwordEt;
    private Button loginBtn;
    private Button biometricBtn;
    private CheckBox enableBiometricCb;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        usernameEt = findViewById(R.id.et_username);
        passwordEt = findViewById(R.id.et_password);
        loginBtn = findViewById(R.id.btn_login);
        biometricBtn = findViewById(R.id.btn_biometric);
        enableBiometricCb = findViewById(R.id.cb_enable_biometric);

        enableBiometricCb.setChecked(BiometricAuthManager.isBiometricEnabled(this));
        biometricBtn.setEnabled(BiometricAuthManager.canAuthenticate(this) && BiometricAuthManager.isBiometricEnabled(this));

        enableBiometricCb.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked) {
                if (!BiometricAuthManager.canAuthenticate(this)) {
                    enableBiometricCb.setChecked(false);
                    BiometricAuthManager.setBiometricEnabled(this, false);
                    biometricBtn.setEnabled(false);
                    return;
                }
                BiometricAuthManager.setBiometricEnabled(this, true);
                biometricBtn.setEnabled(true);
            } else {
                BiometricAuthManager.setBiometricEnabled(this, false);
                biometricBtn.setEnabled(false);
            }
        });

        loginBtn.setOnClickListener(v -> {
            if (performPasswordLogin()) {
                if (enableBiometricCb.isChecked() && BiometricAuthManager.canAuthenticate(this)) {
                    BiometricAuthManager.setBiometricEnabled(this, true);
                }
                goToHome();
            }
        });

        biometricBtn.setOnClickListener(v -> startBiometricUnlock());
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (BiometricAuthManager.isBiometricEnabled(this) && BiometricAuthManager.canAuthenticate(this)) {
            startBiometricUnlock();
        }
    }

    private void startBiometricUnlock() {
        BiometricAuthManager.authenticate(
                this,
                "Unlock",
                "Use your fingerprint to unlock",
                "Use password",
                new BiometricAuthManager.Callback() {
                    @Override
                    public void onSuccess() {
                        goToHome();
                    }

                    @Override
                    public void onFailure() {
                    }

                    @Override
                    public void onError(int errorCode, CharSequence errString) {
                        if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON
                                || errorCode == BiometricPrompt.ERROR_USER_CANCELED
                                || errorCode == BiometricPrompt.ERROR_CANCELED) {
                            return;
                        }
                    }
                }
        );
    }

    private boolean performPasswordLogin() {
        String u = usernameEt.getText() != null ? usernameEt.getText().toString() : "";
        String p = passwordEt.getText() != null ? passwordEt.getText().toString() : "";
        return !u.trim().isEmpty() && !p.trim().isEmpty();
    }

    private void goToHome() {
        Intent i = new Intent(this, MainActivity.class);
        i.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP | Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(i);
        finish();
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class SplashActivity extends AppCompatActivity {

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (BiometricAuthManager.isBiometricEnabled(this) && BiometricAuthManager.canAuthenticate(this)) {
            Intent i = new Intent(this, LoginActivity.class);
            i.putExtra("auto_biometric", true);
            startActivity(i);
            finish();
            return;
        }

        startActivity(new Intent(this, LoginActivity.class));
        finish();
    }
}

